settings.custom_css:
 /*animasi zoom in awal buka link*/
 .info_modalx{
  padding: 10px;
  animation: zoom-in 3s ease-out;
}
/*custom posisi teks nama mempelai -boleh dihapus */
.wdp-mempelai{
    animation: zoom-in 5s ease-out;
}
/* wdp dear to */
.wdp-dear{
    animation: zoom-in 4s ease-out;
}
.wdp-dear:after{
    content: " ";
    display: block;
    animation: zoom-in 4.5s ease-out;
}
.wdp-name{
    animation: zoom-in 7s ease-out;
}
@keyframes zoom-in {
  0% {
    transform: scale(0);
  }
  100% {
    transform: scale(1);
  }
}
/*slide to top */
.removeModals {
    transform: translateY(-200%);
    transition: 2s ease-in-out;
}

:root{
    --first-color: #F6DF75;
    --second-color: #89fffd;
    --size: 500px;
    --speed: 8s;
}
selector{
    overflow: hidden !important;
    display: flex;
    justify-content: center;
    align-items: center;
}
selector:before{
    content: '';
    position: absolute;
    width: var(--size);
    height: 140%;
    background: linear-gradient(var(--first-color), var(--second-color));
      animation: animate var(--speed) linear infinite;
}
@keyframes animate{
    0%{
        transform: rotate(0deg);
    }
    100%{
        transform: rotate(360deg);
    }
}

